// Lógica de agendamento dos lembretes pré-call (fonte única de verdade).
// Usada (a) pelo builder do Enfileirador, que injeta o corpo no Code node do n8n,
// e (b) pelo teste calc.test.mjs. NÃO usar APIs de n8n aqui — JS puro.
//
// calc(inp, nowMs?) -> array de linhas prontas p/ INSERT em fila_precall.
//   inp: { closer, telefone, nome, start_time (ISO UTC), event_uri, is_reschedule }
//   nowMs: opcional (ms) p/ testes determinísticos; default = agora.
function calc(inp, nowMs) {
  const H = 3600 * 1000;
  const start = new Date(inp.start_time);
  const now = nowMs != null ? new Date(nowMs) : new Date();
  const eventUri = inp.event_uri;
  const closer = inp.closer || '';
  const isResched = inp.is_reschedule === true || inp.is_reschedule === 'true';

  const phone = (() => { let d = String(inp.telefone || '').replace(/\D/g, ''); if (!d.startsWith('55')) d = '55' + d; return d; })();
  const nome = (inp.nome || '').trim().split(' ')[0];

  const toBrt = d => new Date(d.getTime() - 3 * H);
  const pad = n => String(n).padStart(2, '0');
  const b = toBrt(start);
  const data = `${pad(b.getUTCDate())}/${pad(b.getUTCMonth() + 1)}`;
  const hora = `${pad(b.getUTCHours())}:${pad(b.getUTCMinutes())}`;

  const T = {
    passo2_inicial: `Opa, tudo bem? Aqui é o ${closer}, do time do JP Bijari. Vi sua aplicação e nossa consultoria está confirmada para ${data} às ${hora}, fechado?`,
    passo2_final: `Já estou dando uma olhada no seu instagram e nas respostas do seu formulário, mas seguinte, consegue me mandar um áudio de até 2 minutos com mais detalhes do seu cenário (objetivo e desafios) e o que você espera resolver na nossa consultoria? Assim consigo te ajudar ainda mais.`,
    passo2_escassez: `Caso você não responda em algumas horas, infelizmente vamos ceder sua vaga para alguém que confirme. Entregamos uma verdadeira consultoria com diagnóstico e plano de ação e o volume de interessados por semana é muito maior que o de vagas disponíveis.`,
    passo3: `Oi ${nome}! Aqui é ${closer}. Estou verificando para ter certeza de que continuamos combinados para a ligação de amanhã, você pode me responder para confirmar?`,
    passo4a: `Fala ${nome}, ${closer} aqui. Já estou fazendo as anotações para a nossa call às ${hora}. Bora com tudo para te ajudar a deixar claros os seus próximos passos.`,
    passo4b: `Lembre de estar em um lugar tranquilo e sem distrações para nossa conversa fluir bem. Falo com você em breve!`,
    passo5: `Fala ${nome}, tudo certo para daqui 1 hora? Vai conseguir conectar comigo? Já fica num lugar tranquilo e sem distrações, pois, vamos falar muito sobre o que você preencheu no formulário e construir junto seu plano de ação!`,
    passo6: `Te vejo em 15 min, fechado? Daqui a pouco te mando o link! 🤝`,
  };

  const link = inp.join_url || '';
  const E = {
    s2: `Sua consultoria está confirmada — ${data} às ${hora}`,
    b2: `<p>Opa, ${nome}, tudo bem?</p><p>Aqui é a equipe do JP Bijari.</p>`
      + `<p>Vi sua aplicação e nossa consultoria está confirmada para ${data}, às ${hora} com o ${closer}.</p>`
      + `<p>Já estamos analisando seu Instagram e as respostas do seu formulário. Mas para eu chegar na call com um diagnóstico mais preciso, me ajuda com uma coisa:</p>`
      + `<p>Nós te mandamos uma mensagem de confirmação no WhatsApp — nos responda com um áudio informando também qual seu objetivo, qual seu maior desafio hoje e o que você espera resolver na nossa conversa.</p>`
      + `<p>Quanto mais contexto nós tivermos, mais fundo conseguimos ir no seu plano de ação.</p>`
      + `<p>Um ponto importante: se você não confirmar nas próximas horas, vamos precisar ceder sua vaga para alguém da fila. Entregamos uma consultoria de verdade — com diagnóstico e plano de ação — e o volume de aplicações por semana é bem maior que o número de vagas.</p>`
      + `<p>Te esperamos lá.<br>Time JP Bijari</p>`,
    s4: `Nossa call é hoje às ${hora}`,
    b4: `<p>Fala, ${nome}.</p>`
      + `<p>Nosso consultor ${closer} já está fazendo as anotações para a nossa call de hoje, às ${hora}, com base no que você preencheu no formulário.</p>`
      + `<p>Bora com tudo para deixar claros os seus próximos passos.</p>`
      + `<p>Dois pedidos rápidos para a conversa render:</p>`
      + `<ol><li>Esteja em um lugar tranquilo, sem distrações — a call é de trabalho, não de bate-papo.</li>`
      + `<li>Se puder, tenha em mente seus números atuais (faturamento, ticket, volume de vendas). Vamos usar isso no diagnóstico.</li></ol>`
      + `<p>Te esperamos lá!<br>Time JP Bijari</p>`,
    s6: `Nos vemos em 15 minutos`,
    b6: `<p>${nome}, tudo certo para daqui a pouco?</p>`
      + `<p>Este é o link da sua call: <a href="${link}">${link}</a></p>`
      + `<p>Nos vemos já já. 🤝<br>Time JP Bijari</p>`,
  };
  const hasEmail = !!(inp.email && String(inp.email).trim());

  function passo4At() {
    let t = new Date(start.getTime() - 6 * H);
    const hb = toBrt(t).getUTCHours();
    if (hb < 8) { const x = toBrt(t); x.setUTCHours(8, 0, 0, 0); t = new Date(x.getTime() + 3 * H); }
    else if (hb >= 20) { return null; }
    return t;
  }

  const rows = [];
  const add = (step, at, msg, channel = 'whatsapp', subject = '', email = '') =>
    rows.push({ step, at, msg, channel, subject, email });
  if (!isResched) {
    add('passo2_inicial', now, T.passo2_inicial);
    add('passo2_final', new Date(now.getTime() + 20000), T.passo2_final);
    add('passo2_escassez', new Date(now.getTime() + 40000), T.passo2_escassez);
  }
  if (start.getTime() - now.getTime() >= 36 * H) add('passo3', new Date(start.getTime() - 24 * H), T.passo3);
  const p4 = passo4At();
  if (p4 && p4 < start) { add('passo4a', p4, T.passo4a); add('passo4b', new Date(p4.getTime() + 20000), T.passo4b); }
  add('passo5', new Date(start.getTime() - 1 * H), T.passo5);
  add('passo6', new Date(start.getTime() - 15 * 60 * 1000), T.passo6);

  if (hasEmail) {
    if (!isResched) add('email_passo2', now, E.b2, 'email', E.s2, inp.email.trim());
    if (p4 && p4 < start) add('email_passo4', p4, E.b4, 'email', E.s4, inp.email.trim());
    add('email_passo6', new Date(start.getTime() - 15 * 60 * 1000), E.b6, 'email', E.s6, inp.email.trim());
  }

  const isImmediate = r => r.step.startsWith('passo2') || r.step === 'email_passo2';
  const out = rows.filter(r => isImmediate(r) || r.at > now);
  return out.map(r => ({
    id: `${eventUri}|${r.step}`, event_uri: eventUri, lead_nome: inp.nome || '', telefone: phone,
    closer, step: r.step, message: r.msg, send_at: r.at.toISOString(), start_time: start.toISOString(),
    channel: r.channel, subject: r.subject, email: r.email,
  }));
}

const items = $input.all();
return items.flatMap(it => calc(it.json).map(r => ({ json: r })));
